import { useEffect, useState } from "react";
import api from "./api"; // 👈 ВАЖНО (используем твой api с токеном)

function Results({ userId, setPage }) {
  const [results, setResults] = useState([]);

  useEffect(() => {
    load();
  }, []);

  const load = async () => {
    try {
      const res = await api.get("/my-results");
      setResults(res.data);
    } catch (err) {
      console.log(err);
      alert("Ошибка загрузки результатов");
    }
  };

  return (
    <div>
      <button onClick={() => setPage("dashboard")}>
        ⬅ Назад
      </button>

      <h2>Мои результаты</h2>

      {results.length === 0 && <p>Нет результатов</p>}

      {results.map((r) => (
        <div key={r.id}>
          {r.isOrganizer
            ? "👑 Организатор квиза"
            : `${r.place} место — ${r.score} очков`}
        </div>
      ))}
    </div>
  );
}

export default Results;
